<?php
namespace App\Http\Requests\Admin\Content;use App\Domain\Equipment\EquipmentType;use App\Domain\WorldCatalog\CatalogStatus;use App\Domain\WorldCatalog\ItemRarity;use App\Domain\WorldCatalog\ItemType;use Illuminate\Foundation\Http\FormRequest;use Illuminate\Validation\Rule;
class ItemRequest extends FormRequest{protected function prepareForValidation(){if(!$this->has('required_level'))$this->merge(['required_level'=>1]);if(!$this->has('character_class_ids'))$this->merge(['character_class_ids'=>[]]);}public function authorize(){return true;}public function rules(){$id=$this->route('item')?$this->route('item')->id:null;return['code'=>['required','string','max:64',Rule::unique('items','code')->ignore($id)],'name'=>'required|string|max:255','description'=>'nullable|string','item_type'=>['required',Rule::in(ItemType::values())],'equipment_type'=>['nullable',Rule::in(EquipmentType::all())],'required_level'=>'required|integer|min:1|max:65535','character_class_ids'=>'nullable|array','character_class_ids.*'=>'integer|distinct|exists:character_classes,id','rarity'=>['required',Rule::in(ItemRarity::values())],'is_stackable'=>'required|boolean','max_stack'=>'required|integer|min:1','status'=>['required',Rule::in(CatalogStatus::values())],'max_health_bonus'=>'required|integer|min:0','attack_bonus'=>'required|integer|min:0','defense_bonus'=>'required|integer|min:0','accuracy_bonus'=>'required|integer|min:0','evasion_bonus'=>'required|integer|min:0','critical_chance_bonus'=>'required|numeric|min:0|max:999.99','attack_speed_bonus'=>'required|numeric|min:0|max:999.99'];}}
